/* 朝雾(自定义适配版)2026-1-9
   作者：咩野(DC@lambkinling)
   请勿二传，倒卖、商用引流、在闲鱼购买的人默认死全家 */

/* 看不清字就把酒馆自带的主要文本颜色改深一些，文本阴影宽度拉到0，不要勾选禁用文本阴影 */

/* 酒馆主题颜色: 
    主要文本→全局字体颜色(包括正文)
    斜体文本→*斜体*外发光颜色，头像旁文案颜色
    下划线文本→“对话”的背景色
    引用文本→“对话”的字体，书名的颜色
    聊天背景→气泡颜色
    UI背景→整体的背景色，包括底栏顶栏
    UI边框→顶栏&底栏图标，菜单页各种标题下拉框按钮的颜色
    如有遗漏纯属我忘了
*/

/* ========== 字体设置 ========== */
/* 全局字体 */
/* 更换字体使用字体管理脚本or直接在此粘贴字体css */

@import url("https://fontsapi.zeoseven.com/5/main/result.css");

body {
    font-family: "ChillKai";
    font-weight: normal;
}

/* 书名单独设置(可选) */
/*
.mes .name_text {
  &::before,&::after {
  font-family: "ChillKai";
  }
}
*/

/* 头像旁文案(可选) */
/*
.mes .avatar::after {
  font-family: "ChillKai";
}
*/

/* ========== 变量控制 ========== */
:root {
  /* 大部分描边的颜色，可以修改百分比，越大越深 */
  --混合: color-mix(in srgb, var(--SmartThemeBorderColor) 50%, #fff);

  --对话背景色: color-mix(in srgb, var(--SmartThemeUnderlineColor) 20%, transparent);
  --标题栏-1: color-mix(in srgb, var(--SmartThemeBorderColor) 50%, transparent);
  --标题栏-2: color-mix(in srgb, var(--SmartThemeBorderColor) 70%, transparent);
  --标题栏-3: color-mix(in srgb, var(--SmartThemeBorderColor) 30%, #fff);

  --小圆角: 5px;
  --中圆角: 8px;

  --内阴影: rgba(255, 255, 255, 0.75);
  --发光: rgba(255, 255, 255, 0.9);
  --外阴影: rgba(0, 0, 0, 0.15);
  --外阴影-浅: rgba(0, 0, 0, 0.08);
}


:root {
  --底栏输入框: "₊⁺₊⊹𝑴𝒊𝒔𝒕𝒊𝒔𝒍𝒆'𝒔𝑬𝒄𝒉𝒐 𓏸˚𓈒⁺₊⁺";
  --底部文字大小: calc(var(--mainFontSize) * 0.75);
  --User消息底部文字: "× × 择 日 再 见 面 × ×";
  --Char消息底部文字: "× × 你 好 明 天 见 × ×";
  --思维链: "• 𝒂𝒏𝒐𝒏𝒚𝒎𝒐𝒖𝒔 𝒍𝒆𝒕𝒕𝒆𝒓 •";
  --名字大小: 0.8rem;
  --名字前缀: "文/";
  --书名大小: 1.1rem;
  --User书名: "《仲夏夜之梦》";
  --Char书名: "《讲文明树新风》";
  --文案字体大小: 0.55rem;
  --User文案: "“是我引诱你吗？我曾经向你说过好话吗？我不是曾经明明白白地告诉过你，我不爱你，而且也不能爱你吗？”";/* 手动换行使用\A换行符 */
  --Char文案: "“我是你的一条狗，狄米特律斯；你越是打我，我越是讨好你。”";
  --User顶部图片: url("https://files.catbox.moe/ibvgek.jpg");
  --Char顶部图片: url("https://files.catbox.moe/ibvgek.jpg");
  --菜单页头像框: url("https://files.catbox.moe/6yta6e.png");
  --加载更多消息: "₊⋆♡₊˚ 𝓣𝓱𝓮𝓻𝓮 𝓲𝓼 𝓷𝓮𝓿𝓮𝓻 𝓪 𝓯𝓲𝓷𝓪𝓵 𝓬𝓱𝓪𝓹𝓽𝓮𝓻 ˚₊♡⋆₊\A- 永远没有完结篇 -";/* 手动换行使用\A换行符 */
}



/* ========== 文本样式 ========== */
/* 对话 */
q {
  position: relative;
  background-image:
    linear-gradient(to right,
    transparent 0%, var(--对话背景色) 20px, var(--对话背景色) calc(100% - 20px), transparent 100%);
  background-size: 100% 50%;
  border-radius: 1px;
  box-shadow: 
    0.8px 0.8px 1px var(--外阴影-浅);
}

/* 斜体 */
em {
  color: #fff !important; 
  text-shadow: 
    0 0 1px var(--SmartThemeEmColor), 
    0 0 2.5px var(--SmartThemeEmColor);
}

/* 删除 */
del {
  color: var(--SmartThemeEmColor);
  text-decoration-color: crimson;
}

/* 行内代码 */
code {
  color: #fff !important;
  background: var(--SmartThemeUnderlineColor) !important;
  border: none;
  box-shadow: 1px 1px 1px var(--SmartThemeUnderlineColor) !important;
}

/* 代码块 */
.hljs,
.mes pre code {
  position: relative;
  border-radius: 3px;
  color: var(--SmartThemeBodyColor) !important;
  font-size: var(--mainFontSize) !important;
  line-height: 1.6;
  border: none;
  box-shadow:
    inset 0 0 12px var(--内阴影),
    1px 1px 2px var(--外阴影) !important;
  background-color: #fff !important;
  background-image: url("https://files.catbox.moe/7bgdl4.png")  !important;
  background-size: 100% auto;
  background-repeat: repeat;
}

/* 引用 */
blockquote {
  background: linear-gradient(to right, #fff, var(--对话背景色), transparent) !important;
  border-color: var(--SmartThemeEmColor) !important;
}

hr {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 75%, transparent);
}




/* ========== 部分通用 ========== */
/* 全局头像(头像框) */
.avatar img,
body.big-avatar .avatar img{
  box-shadow: none;
  border: none;
}
.avatar:not(.mes .avatar):not(
#HotSwapWrapper .avatar) {
  position: relative;
  &::before {
    content: "";
    position: absolute;
    aspect-ratio: 1 / 1;
    width: 140%;
    top: 47%;
    left: 50%;
    transform: translate(-50%, -50%);
    background: var(--菜单页头像框);
    background-size: 100%
  }
}


/* 滚动条 */
::-webkit-scrollbar {
  width: 4px;
}

::-webkit-scrollbar-thumb {
  background:
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--混合) 100%);
  border: 0.2px solid var(--SmartThemeBorderColor) !important;
  box-shadow: none !important;
}

#chat::-webkit-scrollbar {
    display: none;
}

/* 滑动条 */
input[type="range"] {
  background: 
    linear-gradient(185deg, var(--SmartThemeBorderColor) 0%, var(--混合) 100%) !important;
  border-radius: 15px !important;
  height: 5px !important;
  filter: none !important;
  box-shadow: none !important;
}

input[type="range"]::-webkit-slider-thumb {
  filter: none !important;
  border: none !important;
  border-radius: 50%;
  background: 
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--混合) 100%);
  box-shadow: 
    -1px -1px 1px var(--内阴影),
    1px 1px 1px var(--外阴影) !important;
}

/* by nakari */
#chat {
  /* padding-bottom: 20px); 底栏遮住气泡or可视化表格时使用 */
  background: none;
  border: none;
  max-height: calc(100dvh + var(--bottomFormBlockSize));
  height: calc(100dvh + var(--bottomFormBlockSize));
}

body:not(.waifuMode) #sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  min-height: calc(100dvh - var(--bottomFormBlockSize));
}



/* ========== 顶栏 ========== */
#top-bar,
body.no-blur #top-bar {
  box-shadow: none !important;
  outline: 1px solid var(--SmartThemeBlurTintColor) !important;
  /* 顶栏背景图更换请把注.释符号删去(需要的话也可以把下面这一段粘贴到底栏) */
 /* background: url("你的图片链接");
  background-size: cover;
  background-position: center 50%;
  background-repeat: no-repeat; */
}

/* 图标 */
.drawer-icon.fa-fw {
  display: flex;
  overflow: visible;
  justify-content: center;
  font-size: 1.2em; /* 大小 */
}

.drawer-icon.fa-fw::before{
  color: var(--SmartThemeBorderColor); /* 颜色 */
}

/* 图标替换 */
#leftNavDrawerIcon::before { 
  content: "\f0ae";
}

#API-status-top:not(.redOverlayGlow)::before {
  content: "\f0c6";
}

#API-status-top.redOverlayGlow::before {
  content: "\f714" !important;
  color: crimson !important;
}

#advanced-formatting-button .drawer-icon::before {
  content: "\f1dc";
}

#WI-SP-button .drawer-icon::before {
  content: "\f02a";
}

#user-settings-button .drawer-icon::before {
    content: "\f49e";
}

#backgrounds-drawer-toggle .drawer-icon::before {
  content: "\f302";
}

#extensions-settings-button .drawer-icon::before {
  content: "\f1ea";
}

#persona-management-button .drawer-icon::before {
  content: "\f21e";
}

#rightNavDrawerIcon::before {
  content: "\f2b9";
}

#table_drawer_icon.drawer-icon::before {
    content: "\f080";
}

.drawer-icon.fa-fw:hover {
  filter:
    drop-shadow(0 0 1px var(--标题栏-1))
    drop-shadow(0 0 3px var(--标题栏-1)) !important;
  transform: scale(1.15);
}

/* 拓展 */
#extensionTopBar {
  border: none !important;
  border-bottom: 1px solid var(--混合) !important;
  border-radius: 0 0 var(--小圆角) var(--小圆角) !important;
}





/* ========== 底栏输入框 ========== */
/* by NAKARI */
#form_sheld {
  margin: 0 auto !important;
  position: absolute;
  bottom: 5px;  /* 底栏高度 */
}

#form_sheld:has(#send_textarea:focus),
#form_sheld:has(#send_textarea:not(:placeholder-shown)) {
  position: static;
}

/* 底栏 */
#send_form, 
body.no-blur #send_form {
  width: 92%; /* 宽度 */
  border-radius: var(--中圆角);
  padding: 3px;
  border: 1.2px solid var(--SmartThemeBorderColor) !important;
  outline: 1.5px solid var(--混合) !important;
  box-shadow:
    inset 0 0 20px var(--内阴影),
    0 0 10px var(--发光),
    0 0 7px var(--发光);
}

/* 输入框 */
#send_textarea {
  clip-path: none !important;
  border: none;
}

#send_form textarea:focus {
  box-shadow: 
    inset 1px 1px 2px var(--混合),
    inset 0 0 5px var(--发光);
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 15%, transparent);
}

/* 图标 */
#quick-reply-rocket-button,
#send_form .fa-solid {
  font-size: calc(var(--mainFontSize) * 1.25);
  color: var(--混合);
}

#options_button::before {
    content: "\f10d";
}

#extensionsMenuButton::before {
    content: "\f891";
}

#send_but::before {
    content: "\f10e";
}

#mes_stop i::before {
    content: "\f05e";
    color: crimson;
}

#send_textarea::placeholder {
    opacity: 0;
}

#nonQRFormItems {
    position: relative;
    display: flex;
    align-items: center;
}

/* 📌输入框文案 */
#nonQRFormItems::before {
    content: var(--底栏输入框);
    position: absolute;
    left: calc(50% + 10px); /* 左右位置 */
    top: 50%;
    transform: translate(-50%, -50%);
    font-size: 0.7rem;
    color: var(--SmartThemeBorderColor);
    pointer-events: none;
    z-index: 1;
}

#nonQRFormItems:has(#send_textarea:focus)::before,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::before {
    display: none !important;
}

.list-group,
#quickPersonaImg,
.options-content,
#options {
  box-shadow: none !important;
}

.list-group-item .quickPersonaMenuImg {
    box-shadow: none;
    border: none;
}

#qr--bar > .qr--buttons .qr--button {
  border: none !important;
  border-radius: var(--小圆角) !important;
  background: transparent;
  box-shadow:
    1px 1px 2px var(--混合),
    0 0 3px var(--混合) !important;
}





/* ========== 聊天框 ========== */
/* --- 最新回复 --- */
/* 📌与底栏输入框距离 */
.last_mes {
  margin-bottom: 60px !important;
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 0px;
}

.last_mes[is_user="false"] .mes_block {
  margin-bottom: 20px !important;
}


/* ----- 气泡/消息框(整体) ----- */
.mes {
  flex-direction: column;
  position: relative;
  width: calc(100% - 15px); /* 宽度 */
  margin: 15px auto;
  padding: 12px 7px 17px;
  border-radius: var(--小圆角);
  background-color: var(--SmartThemeChatTintColor);
  box-shadow:
    0 0 2px var(--发光),
    0 0 5px var(--发光),
    0 0 3px var(--发光);
}

/* 时间戳 */
.mes .timestamp {
  position: absolute;
  top: calc(100% - 26px); /* 上下位置调整 */
  left: 50%;
  transform: translateX(-50%);
  padding: 2px 5px;
  color: var(--混合);
  background-color: var(--SmartThemeChatTintColor);
  opacity: 1 !important;
}

.last_mes[is_user="false"] .timestamp {
  top: calc(100% - 45px); /* 最新回复的时间戳位置 */
}

/* 📌底部文字装饰 */
.mes .ch_name::before {
  content: var(--User消息底部文字);
  position: absolute;
  transform: translateX(-50%);
  left: 50%;
  font-size: var(--底部文字大小);
  color: var(--混合);
}

.mes[is_user="false"] .ch_name::before {
  content: var(--Char消息底部文字);
}

/* (可选)更换整个气泡的背景图 */
/*
.mes, 
.mes .timestamp {
  background-image: url("https://files.catbox.moe/xswf7x.png")
    ;
  background-size: 100% auto;
  background-repeat: repeat-y;
}
*/


/* --- 📌文字区域 --- */
.mes_block {
  display: flex;
  flex-direction: column;
  overflow: visible;
  transform: none !important;
  padding: 0;
  border-top: 1px dashed var(--混合);
  border-bottom: 3.5px double var(--混合);
  /* 背景图图床更换 */
  background: url("https://files.catbox.moe/xswf7x.png");
  background-size: 100% auto;
  background-repeat: repeat-y;
}

/* 文本框 */
.mes_text {
  padding: 0 2px;
  text-align: justify;
}

.mes[is_user="true"] .mes_text {
  padding-top: 7px;
}

.mes[is_user="true"] p:last-child {
  margin-bottom: 0;
}

.mes_text p:empty {
    display: none;
}

/* 首行缩进 */
.mes_text p {
  text-indent: 2em;
}


/* --- 小铅笔 --- */
.mes_button,
.mes_edit_buttons {
  font-size: calc(var(--mainFontSize) * 1.05);
  filter: none !important;
  color: var(--SmartThemeBorderColor);
}

.mes .menu_button {
  opacity: 1;
  transform: scale(0.85);
  border-radius: var(--中圆角);
  border: none;
  filter: none !important;
  box-shadow:
    0 0 3px var(--发光),
    1px 1px 3px var(--混合),
    inset 0 0 12px var(--内阴影) !important;
}

.mes .fa-star::before {
  content: "\f02b" !important; 
}

#chat .fa-solid.fa-star {
  color: gold !important;
}
.fa-star::before {
    content: "\f004" !important; 
}

.fa-solid.fa-star {
   color: red !important;
}

.mes_edit::before {
    content: "\f00c";
}

.extraMesButtonsHint::before {
    content: "\f00d" !important;
}

/* 小铅笔置底 */
.mes .ch_name {
  order: 1; /* 不要的话删这行 */
  align-items: center;
}

/* 测试中 */
/*.ch_name:has(.mes_edit_buttons:not([style*="display: none"]))::before,*/
.ch_name:has(.extraMesButtonsHint[style*="opacity: 0"])::before {
  display: none !important;
}

/* --- 思维链 --- */
.mes_reasoning_header {
  background-color: transparent;
  margin: 0 auto;
}

.mes_reasoning_arrow {
  display: none;
}

/* 📌思维链文字自定义 */
.mes_reasoning_header_title {
  font-size: 0;
  &::before {
    content: var(--思维链);
    font-size: calc(var(--mainFontSize) * 0.9);
    background: var(--SmartThemeChatTintColor);
    color: var(--SmartThemeEmColor);
    border-radius: var(--小圆角);
    padding: 2px 6px; /* 高&宽 */
    box-shadow:
      0 0 1px var(--混合),
      1px 1px 2.5px var(--混合),
      inset 0 0 6px var(--内阴影);
  }
}

@media (max-width: 768px) {
  .mes_reasoning_details {
    position: relative;
}

  .mes_reasoning_details[open] {
  width: 100%;
}

  .mes_reasoning {
    width: 100%;
    max-height: 500px; /* 思维链内容高度 */
    overflow: hidden auto;
    font-size: calc(var(--mainFontSize) * 0.9);
    border-radius: var(--小圆角);
    border: 1px dashed var(--SmartThemeBorderColor);
    background: color-mix(in srgb, var(--SmartThemeBorderColor) 15%, #fff);
  }

  .mes_reasoning_actions {
     position: absolute;
     right: 2px;
     top: 2px;
     z-index: 10;
     flex-shrink: 0;
  }
}




/* --- 📌书名号 & 名字 --- */
.mes .name_text {
  position: absolute;
  top: 75px; /* 上下位置① */
  left: 12%; /* 左右 */
  writing-mode: vertical-rl;
  color: var(--SmartThemeQuoteColor); /* 颜色 */
  font-size: var(--名字大小);
  &::before {
    content: var(--名字前缀);
  }
  &::after {
    content: var(--User书名);
    font-size: var(--书名大小);
    position: absolute;
    white-space: nowrap;
    top: -75px; /* 上下位置② */
    right: 100%;
    margin-right: 5px;
  }
}

/* Char书名 */
.mes[is_user="false"] .name_text::after {
  content: var(--Char书名);
}


/* --- 📌头像区域(图床链接更换) --- */
.mesAvatarWrapper {
  display: flex;
  align-self: flex-start;
  align-items: flex-end;
  justify-content: flex-end;
  width: 100%;
  height: 170px; /* 整体高度调整① */
  flex: 0 0 auto;
  gap: 5px;
  margin-bottom: 2px;
  padding-bottom: 5px !important;
  border-bottom: 1.2px solid var(--混合);
  &::before {
    content: "";
    position: absolute;
    top: 8px;
    right: 8px;
    width: 77%;/* 图片宽度调整 */
    height: 130px; /* 图片高度调整 */
    background: var(--User顶部图片); 
    background-repeat: no-repeat;
    background-size: 100% auto;
    background-position: 100% 70%; /* 图片上下显示位置(第二个百分比) */
    border-radius: var(--小圆角);
    box-shadow: -1px 2px 3px var(--外阴影);
  }
}

/* Char图片 */
.mes[is_user="false"] .mesAvatarWrapper::before {
  background: var(--Char顶部图片);
  background-repeat: no-repeat;
  background-size: 100% auto;
  background-position: 100% 50%; /* 图片上下显示位置(第二个百分比) */
}

/* 📌头像旁文案 */
.mes .avatar {
  position: relative;
  bottom: -8px;
  &::after {
    content: var(--User文案);
    white-space: pre-wrap;
    font-size: var(--文案字体大小);
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    margin-left: -5px;
    color: var(--SmartThemeEmColor);
  }
}

/* char文案 */
.mes[is_user="false"] .avatar {
  position: relative;
  &::after {
    content: var(--Char文案);
  }
}

/* 头像 */
.mes .avatar img {
  bottom: 5px;
  transform: scale(0.55);
  outline: 1px solid var(--混合); 
  outline-offset: 2px;
}

/* --- 楼层+计时器+tokens --- */
.mes .mesIDDisplay:not(:empty),
.mes .mes_timer:not(:empty),
.mes .tokenCounterDisplay:not(:empty) {
  opacity: 0.75;
  font-size: 0.7em;
  color: var(--混合);
}

.mes .mes_timer:not(:empty),
.mes .tokenCounterDisplay:not(:empty) {
  &::before {
    content: "/  ";
    margin-left: 1px;
    color: var(--SmartThemeEmColor);
  }
}


/* --- 左右箭头 --- */
.swipe_right,
.swipe_left {
  opacity: 0.75;
  color: var(--混合);
  font-size: 1.2em;
}

.swipe_right::before {
  content: "\f101";
}

.swipe_left::before {
  content: "\f100";
 }

.swipeRightBlock {
  flex-direction: row-reverse;
  bottom: 10px; /* 右箭头高度 */
  margin-right: 15px;
}

/* 左箭头高度 */
.swipe_left {
