/* ========== 菜单抽屉 ========== */
/* --- 抽屉页背景 --- */
body .drawer-content {
  box-shadow: none;
  border-radius: 0 0 8px 8px;
  border-color: var(--SmartThemeBlurTintColor);
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  background: url("https://files.catbox.moe/e5j6hn.jpg"),
    #fff;
  background-size: cover;
  background-repeat: no-repeat;
}

/* 预设页 & 角色管理页 */
@media (max-width: 600px) {
  #left-nav-panel,
  #right-nav-panel {
    max-height: calc(100dvh - var(--topBarBlockSize));
    border-radius: 0 0 8px 8px;
    border-color: var(--SmartThemeBlurTintColor);
    border-bottom: 1px solid var(--SmartThemeBorderColor);
    padding-right: 0;
  }
}

#rm_button_characters {
  font-size: 1.2em;
}

/* 反代警告 */
.reverse_proxy_warning {
    border-color: crimson !important;
    border-radius: var(--小圆角) !important;
    background-color: transparent !important;
}

/* --- 标题栏 --- */
.standoutHeader,
.inline-drawer-header,
#top-settings-holder h4,
#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header {
  filter: none !important;
  padding: 5px 8px;
  margin-bottom: 5px;
  border-radius: 5px;
  border: 0.8px solid var(--SmartThemeBorderColor);
  background:
    radial-gradient(55% 105% ellipse at left top, var(--标题栏-2), transparent),
    radial-gradient(35% 55% ellipse at 60% 110%, var(--内阴影), transparent),
    radial-gradient(120px circle at right center, var(--标题栏-1), transparent),
    var(--标题栏-3);
  box-shadow:
    0.8px 0.8px 0 0.5px var(--混合),
    inset 0 0 12px var(--内阴影),
    inset 0 0 4px var(--内阴影);
}

/* 箭头 */
.inline-drawer-icon {
  color: var(--SmartThemeBorderColor);
  filter: 
    drop-shadow(0 0 1px var(--发光))
    drop-shadow(0 0 4px var(--发光)) !important;
  opacity: 0.75;
  font-size: 1em;
}

.inline-drawer-icon::before {
  content: "\f56b" !important;
}

.inline-drawer-icon.up::before {
  content: "\f52d" !important;
}

#openai_api > h4.margin0 {
  margin-bottom: 8px;
}

#UI-presets-block {
  padding-top: 5px;
  gap: 2px;
}

div[name="themeElements"] > div.inline-drawer.wide100p > div.inline-drawer-toggle.inline-drawer-header {
  margin-top: 10px;
}


/* --- 按钮 --- */
.menu_button:not(.mes_edit_buttons *) {
  box-shadow: 
    inset 0 0 1px var(--标题栏-1),
    1px 1px 2px var(--混合),
    0 0 5px var(--发光);
  background: ;
  color: var(--SmartThemeBorderColor);
  border: none;
  filter: none !important;
}

#bulkDeleteButton,
#delete_button,
#persona_delete_button,
#world_popup_delete,
.menu_button.popup-button-ok,
#delete_connection_profile,
#delete_oai_preset,
#dialogue_del_mes_ok,
.mes_edit_cancel.menu_button,
.mes_edit_buttons .mes_edit_delete {
  background:  crimson !important;
  color: rgba(0, 0, 0, 1) !important;
}


/* --- 勾选框 --- */
input[type="checkbox"] {
  background: var(--SmartThemeBlurTintColor);
  border-radius: 3px;
  filter: none;
  border: none;
  outline: none;
  box-shadow: inset 0 0 3px var(--标题栏-3) !important;
}

.checkbox_label {
  display: flex;
  align-items: center;
}

input[type="checkbox"]:checked {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 30%,  #fff) !important;
  box-shadow: inset 0 0 4px var(--内阴影) !important;
}

/* by c一串(晚晚) */
input[type="checkbox"]::before {
  box-shadow: inset 1em 1em var(--标题栏-1);
}


/* --- 下拉框 --- */
select.text_pole,
select {
  outline: none !important;
  border: none;
  border-radius: var(--小圆角);
  box-shadow:
    1px 1px 2px var(--混合),
    inset 0 0 15px var(--内阴影);
  background-color: color-mix(in srgb, var(--SmartThemeBorderColor) 25%, #fff);
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path fill="%234B831E" d="M5.5 7l4.5 4.5 4.5-4.5 1.5 1.5-6 6-6-6z"/></svg>'); /* 📌下拉箭头: 修改path fill="%23B6B6B6(改%23后面六位hex颜色编码)"*/
  background-position: right 2px center;
  background-repeat: no-repeat;
  background-size: 1.2em;
}

#tag_import_setting {
  margin-top: 5px;
}


/* --- 输入框 --- */
input:not([type]),
input[type="text"],
input[type="search"],
input[type="number"],
textarea.text_pole,
textarea.textarea_compact,
textarea:not(#send_textarea) {
  border: none;
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 15%, #fff);
  box-shadow: 
    1px 1px 2.5px var(--混合),
    inset 0 0 15px var(--内阴影);
  &:hover {
    outline: none;
    box-shadow: 
      inset 1px 1px 1px var(--混合),
      inset 0 0 2px var(--混合);
    background: color-mix(in srgb, var(--SmartThemeBorderColor) 5%, #fff);
  }
}


/* --- 弹窗 --- */
#select_chat_popup,
.popup {
  background: url("https://files.catbox.moe/e5j6hn.jpg"),
    #fff;
  background-size: cover;
  background-repeat: no-repeat;
  border-radius: var(--小圆角);
  border: none;
  box-shadow:
      inset 0 0 15px var(--内阴影),
      1px 1px 5px var(--发光),
      0 0 6px var(--混合) !important;
}

#dialogue_popup_text {
    padding-right: 5px;
}

.popup-content:has(#showRawPrompt) {
    overflow-y: auto;
}

/* 通知提示框 */
div.toast.toast-success {
  background-color: var(--混合) !important;
  border-radius: var(--小圆角) !important;
  color: var(--SmartThemeBodyColor) !important;
  box-shadow: 
    inset 0 0 20px var(--发光),
    1px 1px 5px var(--发光),
    0 0 6px var(--混合) !important;
}

/* --- 预设页 --- */
.range-block > .toggle-description {
  margin-right: 0;
}

.range-block-title {
  text-align: left;
}

