/* ----- 拓展页 ----- */
#tavern_helper [data-folder-id="f8c1b0d6-829c-40a7-b352-38457ef75e9b"] {
  background: var(--混合);
}

/* 限制正则拖拽触发区域 - 仅移动端和平板 */
@media (hover: none) and (pointer: coarse) {
  .regex-script-label {
    pointer-events: none;
  }

  .regex-script-label > *:not(.regex_script_name) {
    pointer-events: auto;
  }

  .regex-script-label .drag-handle {
    pointer-events: auto;
    padding: 6px 10px; /* 调整把手大小 */
  }
}

.regex-script-label {
  border-radius: 3px !important;
  border: 0.8px solid var(--混合) !important;
  background: var(--内阴影);
}
.regex-script-label:has(.disable_regex:not(:checked)) {
    background: color-mix(in srgb, var(--SmartThemeBorderColor) 20%, #fff);
    box-shadow: 
      1px 1px 1px var(--混合),
      inset 0 0 15px var(--内阴影);
}

.regex_script_name {
  white-space: normal;
}

.regex-script-label.flex-container {
  align-items: center;
}

.regex-toggle-on {
  color: var(--标题栏-1);
}

/* 拓展页输入助手 */
.example-extension_block {
  gap: 0 !important;
  margin: 0 !important;
}
.integrated-button-row {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 10%, var(--内阴影)) !important;
  border-radius: var(--小圆角) !important;
  padding: 1px 7px!important;
}

.integrated-button-row > *:not(.drag-handle):not(input[type="checkbox"]):not(label) {
  transform: scale(0.8);
}

/* --- 用户管理器 --- */
#user_avatar_block .avatar-container.selected {
  background: var(--混合);
  border: none !important;
  border-radius: var(--小圆角);
  box-shadow:
    2px 2px 4px var(--混合),
    inset 0 0 15px var(--内阴影);
}

#user_avatar_block .avatar-container.selected .ch_name {
  background: var(--内阴影);
  border-radius: var(--小圆角);
  color: var(--SmartThemeBorderColor);
  padding: 1px;
  box-shadow: inset 0 0 4px var(--混合);
}

/* ----- 角色管理器 ----- */
.character_select {
  margin-top: calc(var(--mainFontSize) * 0.5);
}

.character_select.is_fav {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 10%, #fff);
  border-radius: var(--小圆角);
  box-shadow:
    0 0 4px var(--发光),
    1px 1px 4px var(--混合),
    0 0 2px var(--混合);
}

.character_select.is_fav .avatar {
  outline: none;
}

.character_select.is_fav .ch_name {
  border-radius: 20px;
  max-width: 50%;
  padding: 0 10px;
  background: var(--混合);
  color: var(--SmartThemeQuoteColor);
  box-shadow:
    0 0 4px var(--混合),
    inset 0 0 8px var(--内阴影);
}

.tag.actionable {
  min-height: calc(var(--mainFontSize) * 1.75);
  min-width: calc(var(--mainFontSize) * 1.75);
  margin: 0 auto 3px;
  border: 1px solid var(--混合) !important;
  filter: none;
  box-shadow: 
    inset 0 0 2px var(--内阴影),
    1px 1px 2px var(--混合),
    0 0 2px var(--混合) !important;
}

/* 角色收藏区 */
#CharListButtonAndHotSwaps {
  margin-bottom: calc(var(--mainFontSize) * 0.05);
}

#HotSwapWrapper {
  overflow: hidden;
}

#HotSwapWrapper > div {
  overflow: auto hidden; 
  flex-wrap: nowrap;
  max-height: calc(100vh + 20px);
}

#HotSwapWrapper .avatar {
  outline: 1px solid var(--混合);
  outline-offset: 2px;
  transform: scale(0.9);
}

.avatars_inline {
  gap: 3px;
  flex-wrap: nowrap;
  overflow: visible;
}

/* 加载消息 */
#show_more_messages {
  font-size: 0;
  background-color: var(--SmartThemeChatTintColor);
  padding: 2px 8px;
  outline: none;
  border-radius: var(--小圆角);
  box-shadow:
    0 0 2.5px var(--混合),
    1px 1px 2.5px var(--混合),
    inset 0 0 15px var(--内阴影);
  line-height: 1.6;
}

#show_more_messages::after {
  content: var(--加载更多消息);
  white-space: pre;
  color: var(--SmartThemeEmColor);
  font-style: italic;
  font-size: calc(var(--mainFontSize) * 0.75);
}

